ur.fetchAndSaveTurtle = async function(fetchURI, force){
  return new Promise(resolve => {
    ur.aLoadURI(fetchURI, null, { force: force }).then((result) => { // Can force to get the data remotely
      if(result){
        result.forEach(statem => {
          store.state.rs.rdfStore.add(statem);
        });
        store.state.rs.urisFetched.push(fetchURI);
        resolve(true);
      } else {
        console.log("Error: Problems with fetching URI!!!");
        resolve(false);
      }
    });
  });
}

ur.aLoadURI = async function (uri, doc, options) {
    console.log("aLoadURI", uri, doc);
    if (!options) {
      options = {}
    }
    options.fetch = window.solid.hyperFetch
    options.headers = {hypergraph: 'U2FsdGVkX1/S0rANmPZVe3xCIXvlGoGnGudwlp4wFSMFtte++kYYPt0l4B4407c+'} // Should be set in rdfstore.js - do not work in rdfstore.js
    if (uri) {
      try {
          await rdfFetcher.load(uri, options);
          var statements = u.unique(rdfStore.match(null, null, null, $rdf.sym(uri)));
          return statements;
      } catch (err) {
          console.log("Cant load URI: ", uri, err);
      }
    } else {
      console.log("ERROR: bad URI to loadURIa");
    }
}

