ur.parseLinkHeader = function(item){
  var result = {}
  var uri = u.getURI(item)
  if (uri){
    var link = rdfFetcher.getHeader($rdf.sym(uri),"Link")
    if (Array.isArray(link)){
        link = link[0]
        if (typeof(link) === 'string'){
          var links = link.split(",")
          if (Array.isArray(links)){
              links.forEach(function (lk){
                var row = lk.split(";")
                if (Array.isArray(row)){
                  var iri = row[0].trim()
                  var URI = u.getURI(iri)
                  if (URI){
                    var Type = row[1]
                      if (typeof(Type) === 'string'){
                          Type = Type.split("=")
                          if (Array.isArray(Type)){
                        Type = Type[1]
                        if (typeof(Type) === 'string'){
                            Type = Type.replaceAll('"',"")
                            if (result[Type]){
                              result[Type].push(URI)
                            } else {
                              result[Type] = [URI]
                            }
                        }
                      }
                    }
                  }
                }
              })
          }
        }
    }
  }
  return result
}

ur.checkIfContainLoopInStore = function(pstore, compare){
  const URIlist = [];
  const foundIssues = [];
  let arr1 = pstore.match(null, ns.SIO("SIO_000202"), null);
  let arr2 = pstore.match(null, ns.DUL("hasPart"), null);
  let arr3 = pstore.match(null, ns.LDP("contains"), null);
  let arr4 = pstore.match(null, ns.NEO("t_1pr4n"), null);
  for (var k=0; k<20; k++) { // Goes down 20 levels of inheritance
    let foundNewContains = false;
    arr1.concat(arr2).concat(arr3).concat(arr4).forEach(quad => {
      const foundSubject = quad.subject.value;
      const foundObject = quad.object.value;
      let foundPredicate = "sio:SIO_000202";
      if(quad.predicate.value == ns.DUL("hasPart").value) foundPredicate = "dul:hasPart";
      if(quad.predicate.value == ns.LDP("contains").value) foundPredicate = "ldp:contains";
      if(quad.predicate.value == ns.NEO("t_1pr4n").value) foundPredicate = "neo:t_1pr4n";
      let subobjset = foundSubject+" "+foundPredicate+" "+foundObject+"##"; // The ## marks the end of the hierarchy to know what is the previous URI looked at.
      let found = false;
      let addString = " "+foundPredicate+" "+foundObject+"##";
      if(URIlist){
        for (var j = 0; j < URIlist.length; j++) {
          if(URIlist[j].includes(foundSubject+"##") && !URIlist.includes(URIlist[j].replace("##", addString))){
            found = true;
            foundNewContains = true
            if(URIlist[j] == foundObject){
              console.log("Error. Loop found!!!!!");
              foundIssues.push(URIlist[j].replace("##", addString));
              console.log(foundIssues);
              j = URIlist.length+1; // Break out of inheritance loop
              k=20; // Break out of URIlist loop
              return true;
            }
            URIlist[j] = URIlist[j].replace("##", addString);
            URIlist.push(URIlist[j]); // Create duplicate of hierarchy if several children
          }
        }
      }
      if(!found) {
        URIlist.push(subobjset);
      }
    });
    if(!foundNewContains) return;
  }
  // Compare hierarhies together
  if(compare){
    for (var ul = 0; ul < URIlist.length; ul++) {
      // Get first and last URI
      let firstURI = URIlist[ul].split(' ')[0];
      let lastURI = URIlist[ul].split(' ').pop().replace("##", "");
      //console.log("FirstURI: "+firstURI+" LastURI: "+lastURI);
      for (var uls = 0; uls < URIlist.length; uls++) {
        if(URIlist[uls]!=URIlist[ul]){
          let firstURIc = URIlist[uls].split(' ')[0];
          let lastURIc = URIlist[uls].split(' ').pop().replace("##", "");
          if(firstURI==firstURIc&&lastURI==lastURIc){
            console.log("Error. Loop found in paralell hierarchy!!!!!");
            foundIssues.push(URIlist[uls]);
            foundIssues.push(URIlist[ul]);
            console.log(foundIssues);
            uls = URIlist.length+1; // Break out of URIlist outer loop
            ul = URIlist.length+1; // Break out of URIlist loop
            return true;
          }
        }
      }
    }
  }
  //console.log(URIlist);
  if(foundIssues.length>0){
    return true;
  } else {
    return false;
  }
}

