// Tail recursive nesting of hierarchies
ur.getParentsNested = function(uri, predicateTypes){
  let hierarchiesList = [[uri]];
  let parentsfound = false;
  let currentURIs = [uri];
  let parentURIs = [];
  for(var lvl =0 ; lvl < 50; lvl++) { // Set limit of hierarchy size to a number to prevent infinite loop
    parentsfound = false;
    currentURIs.forEach(currentURI => {
      let duplicateAdded = 1;
      predicateTypes.forEach(predicate => { // Loop through all predicate parents
        rdfStore.match(null, predicate, $rdf.sym(currentURI)).forEach((triple, index) => { // Find the parents of current URI
          for (var hli = 0; hli < hierarchiesList.length; hli++) { // Loop through the hierachies made
            if(index >= 1){ // Check if this is second parent, and hierarchy needs to be duplicated
              if(a.getSecondLastElement(hierarchiesList[hli]) == currentURI && duplicateAdded == index) { // Compare second last element
                hierarchiesList.push(a.removeLastElement(hierarchiesList[hli])); // Create duplicate of hierarchy without last element of previous hierarchy
                duplicateAdded = index+1; // Will make sure duplicates are added only once for each duplicate parent
              }
            }
            if(a.getLastElement(hierarchiesList[hli]) == currentURI) { // Check if last item in array is current URI focus
              if(hierarchiesList[hli].includes(triple.subject.value)){
                console.log("Loop found!!");
                hierarchiesList[hli].push(triple.subject.value);
                return a.reverseSubArrays(hierarchiesList); // Break out of function if loop is found
              }
              hierarchiesList[hli].push(triple.subject.value);
            }
          }
          parentURIs.push(triple.subject.value);
          parentsfound = true;
        });
      });
    });
    currentURIs = parentURIs;
    parentURIs = [];
    if(!parentsfound){
      return a.reverseSubArrays(hierarchiesList);
    }
  }
  return a.reverseSubArrays(hierarchiesList);
}

// Tail recursive nesting of hierarchies
ur.getChildrenNested = function(hlist, predicateTypes){
  let hierarchiesList = hlist;
  let childrenfound = false;
  let currentURIs = [];
  hlist.forEach(subArray => {
    let newCurrentURI = subArray[subArray.length - 1];
    if(!currentURIs.includes(newCurrentURI)) currentURIs.push(newCurrentURI); // Add current tail level of URIs from input array
  });
  let childrenURIs = [];
  for(var lvl =0 ; lvl < 50; lvl++) { // Set limit of hierarchy size to a number to prevent infinite loop
    childrenfound = false;
    currentURIs.forEach(currentURI => {
      let duplicateAdded = 1;
      predicateTypes.forEach(predicate => { // Loop through all predicate children
        rdfStore.match($rdf.sym(currentURI), predicate, null).forEach((triple, index) => { // Find the children of current URI
          for (var hli = 0; hli < hierarchiesList.length; hli++) { // Loop through the hierachies made
            if(index >= 1){ // Check if this is second parent, and hierarchy needs to be duplicated
              if(a.getSecondLastElement(hierarchiesList[hli]) == currentURI && duplicateAdded == index) { // Compare second last element
                hierarchiesList.push(a.removeLastElement(hierarchiesList[hli])); // Create duplicate of hierarchy without last element of previous hierarchy
                duplicateAdded = index+1;  // Will make sure duplicates are added only once for each duplicate parent
              }
            }
            if(a.getLastElement(hierarchiesList[hli]) == currentURI) { // Check if last item in array is current URI focus
              if(hierarchiesList[hli].includes(triple.object.value)){
                console.log("Loop found!!");
                hierarchiesList[hli].push(triple.object.value);
                return hierarchiesList; // Break out of function if loop is found
              }
              hierarchiesList[hli].push(triple.object.value);
            }
          }
          childrenURIs.push(triple.object.value);
          childrenfound = true;
        });
      });
    });
    currentURIs = childrenURIs;
    childrenURIs = [];
    if(!childrenfound){
      return hierarchiesList;
    }
  }
  return hierarchiesList;
}

