ur.modifyTurtle = function(turt){
  turt = ur.checkPrefixes(turt);
  turt = turt.replaceAll('@prefix : <#>.\n', '');
  turt = turt.replace(/(>)\n/g, '$1 '); // Replaces blank node <> characters.
  turt = turt.replace(/(>\s)\s+/g, '$1'); // Replace blank spaces after > character
  turt = turt.replace(/([^\s])([;.])\s/g, '$1 $2\n'); // Add blank spaces before split
  turt = turt.replace(/<(_:\w+)>/g, '$1'); // Replaces blank node <> characters.
  //turt = turt.replaceAll("^^<neo:a_matrix-3m>", "");
  turt = turt.replaceAll('^^neo:a_matrix-3m"', '"^^neo:a_matrix-3m');
  turt = turt.replace(/(\n)\n/g, '$1'); //Removes double line breaks.
  return turt;
}

ur.checkPrefixes = function (turt){
  try{
    let prefixarray = turt.split(/\r\n|\n/);
    for (var i=1; i<prefixarray.length; i++) {
      if (prefixarray[i].includes("@prefix")) {
        let prefix = prefixarray[i].replace('@prefix ', '');
        prefix = prefix.substring(0, prefix.indexOf(":")+1);
        let prefixuri = prefixarray[i].substring(prefixarray[i].indexOf("<")+1, prefixarray[i].indexOf(">"));
        prefixarray[i] = { prefix:prefix , uri:prefixuri };
        //console.log(prefixarray[i].prefix);
        // Replace all prefixes that is using the i with whole URI
        turt = turt.replaceAll(prefixarray[i].prefix+'i', '<'+prefixarray[i].uri+'i>');
        turt = turt.replaceAll(prefixarray[i].prefix+'y_system', '<'+prefixarray[i].uri+'y_system>');
        turt = turt.replaceAll(prefixarray[i].prefix+'tag', '<'+prefixarray[i].uri+'tag>');
      }
    }
    return turt;
  } catch (error){
    console.log(error)
  }
}

