    async getRoomZonesOnEachSideOfDoor(modelID, doorID, doorMesh){
      const props = await ifcLoader.ifcManager.getItemProperties(modelID, doorID);
      const doorWidth = props.OverallWidth.value;
      /*console.log("Properties:")
      console.log(props)
      console.log("Door name: "+props.Name.value);
      console.log("Door height: "+props.OverallHeight.value);
      console.log("Door width: "+props.OverallWidth.value);
      console.log("Door TAG: "+props.Tag.value);*/
      let location = this.getMeshCenterPoint(doorMesh);
      this.createPlaceMarker(location, 0xFF0000);

      let heightAboveGround = bmu.getMeshHeightAboveGround(doorMesh);
      await this.getRoomZonesFromStorey(modelID, {x:location.x,y:heightAboveGround,z:location.y});

      const firstOffsetPoint = new Vector3(doorWidth/1500, 1, 0); // Can change the number value to change radius of circle
      const firstPointOnCircle = location.clone().add(firstOffsetPoint);
      this.createPlaceMarker(firstPointOnCircle, 0x00FF00, false);
      const foundRooms = [];
      store.state.bv.scene.getObjectByName("buildingbox").children.forEach((roomMesh, i) => {
        if(bmu.checkIfPointInsideMesh(firstPointOnCircle, roomMesh)){
          if(!foundRooms.includes(roomMesh.name)) foundRooms.push(roomMesh.name);
        }
      });
    
      // Do room checks for each 45 degrees while rotating around door
      const axis = new Vector3(0, 1, 0);
      const angle = Math.PI / 4;
      for(let i=0; i<=6; i++){
        const currentCheckPoint = location.clone().add(firstOffsetPoint.applyAxisAngle(axis, angle));
        this.createPlaceMarker(currentCheckPoint, 0x0000FF, false);
        store.state.bv.scene.getObjectByName("buildingbox").children.forEach((roomMesh, i) => {
          if(bmu.checkIfPointInsideMesh(currentCheckPoint, roomMesh)){
              if(!foundRooms.includes(roomMesh.name)) foundRooms.push(roomMesh.name);
          } else {
            //console.log("Not inside.")
          }
        });
      }
      return foundRooms;
    },
    async getRoomZonesFromStorey(modelID, position={x:0,y:0,z:0}){
      bmu.unloadGeometryUsingTag("NMH.Y.SYKEHUS.HN.H.MOIRANA.SJOFORSGATA", ["HOVEDBYGG"]);
      const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");

      const spaceIDs = await ifcLoader.ifcManager.getAllItemsOfType(modelID, IFCSPACE);
      const spaceMeshes = ifcu.getAllSubsetMeshes(spaceIDs, modelID, ifcLoader);
      let roomSpaceArray = [];
      for(let i = 0; i<=spaceIDs.length-1; i++){
        //console.log(spaceMeshes[i]);
        roomSpaceArray.push({expressID: spaceIDs[i], elementID: spaceMeshes[i].id });
      }

      const material = new MeshStandardMaterial( { color: 0xAAAAFF, metalness: 0, roughness: 0 } );

      // Function for getting lowest heightAboveGround and remove spaces from other storeys
      for(let i = 0; i<=spaceMeshes.length-1; i++){
        let heightAboveGround = bmu.getMeshHeightAboveGround(spaceMeshes[i]);
        //console.log(heightAboveGround);
        if(heightAboveGround!=position.y){
          roomSpaceArray.forEach(element => {
            if(element.elementID==spaceMeshes[i].id){
              a.removeValueFromArray(spaceIDs, element.expressID);
            }
          });
        } else {
          const props = await ifcLoader.ifcManager.getItemProperties(modelID, spaceIDs[i]);
          const roomMesh = ifcu.getAllSubsetMeshes([spaceIDs[i]], modelID, ifcLoader)[0];
          try { 
            roomMesh.name = props.Name.value;
            if(store.state.bv.scene.getObjectByName(props.Name.value)) return; // Do not draw rooms if already exist.
          } catch(error){}
          roomMesh.material = material.clone();
          roomMesh.material.side = DoubleSide; // Must have doubleside for making the raycaster work - Espen.
          buildingbox.add(roomMesh);
        }
      }

      this.RENDER();

      //console.log("Roomspaces:");
      //console.log(spaceIDs);
      /*const subset = ifcLoader.ifcManager.createSubset({
        ids: spaceIDs,
        modelID,
        removePrevious: true,
        customID
      });
      subset.name = "roomspaces";*/
      //buildingbox.add(subset);
    },
    getMeshCenterPoint(mesh){
      let maxX = -100000, minX = 100000, maxY = -100000, minY = 100000;
      for(let y = 0; y<=mesh.geometry.attributes.position.array.length-3; y=y+3){
        maxX = Math.max(mesh.geometry.attributes.position.array[y], maxX);
        minX = Math.min(mesh.geometry.attributes.position.array[y], minX);
      }
      for(let y = 2; y<=mesh.geometry.attributes.position.array.length; y=y+3){
        maxY = Math.max(mesh.geometry.attributes.position.array[y], maxY);
        minY = Math.min(mesh.geometry.attributes.position.array[y], minY);
      }
      return new Vector3((maxX+minX)/2, 0, (maxY+minY)/2);
    },
    async getIFCElementPosition(expressID, modelID){
        const spaceProperties = await ifcLoader.ifcManager.getItemProperties(modelID, expressID);
        const positionProperties = await ifcLoader.ifcManager.getItemProperties(modelID, spaceProperties.ObjectPlacement.value);
        const relativePlacement = await ifcLoader.ifcManager.getItemProperties(modelID, positionProperties.RelativePlacement.value);
        const location = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.Location.value);
        console.log(location);
        return location;
    },
    async getIFCElementLocationTranslated(expressID, modelID){
        const spaceProperties = await ifcLoader.ifcManager.getItemProperties(modelID, expressID);
        const positionProperties = await ifcLoader.ifcManager.getItemProperties(modelID, spaceProperties.ObjectPlacement.value);
        console.log("objectplacement:")
        console.log(positionProperties);
        const relativePlacement = await ifcLoader.ifcManager.getItemProperties(modelID, positionProperties.RelativePlacement.value);
        const PlacementRelTo = await ifcLoader.ifcManager.getItemProperties(modelID, positionProperties.PlacementRelTo.value);
        console.log("PlacementRelTo:")
        console.log(PlacementRelTo);
        const relToRelativePlacement = await ifcLoader.ifcManager.getItemProperties(modelID, PlacementRelTo.RelativePlacement.value);
        const relToLocation = await ifcLoader.ifcManager.getItemProperties(modelID, relToRelativePlacement.Location.value);
        const relTocoordinates = relToLocation.Coordinates;
        const location = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.Location.value);
        const ifcAxis = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.Axis.value);
        const refDirection = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.RefDirection.value);
        const directionRatios = refDirection.DirectionRatios;
        const axisDirectionRatios = ifcAxis.DirectionRatios;
        const coordinates = location.Coordinates;
        var point1 = (coordinates[0].value/100);
        var point2 = (coordinates[1].value/100);
        console.log("Coordinates:")
        console.log(coordinates);
        // Functionality to find rotation START ---------------------
        const inRotation = { x:directionRatios[0].value, y:directionRatios[1].value, z:directionRatios[2].value };
        const inAxis = { x: axisDirectionRatios[0].value, y:axisDirectionRatios[1].value, z:axisDirectionRatios[2].value };
        const crossProduct = ifcu.v3cross(inRotation, inAxis);
        const myAxis = { x:0, y:-1, z:0 };

        var angle = ifcu.getAngleRadians(crossProduct.x, crossProduct.y, inRotation.x, inRotation.y);
        var angle2 = ifcu.getAngleRadians(inAxis.x, inAxis.y, myAxis.x, myAxis.y);
        angle = (angle2-angle)+(Math.PI/4);
        // Functionality to find rotation END ---------------------
        const rotatedPoints = ifcu.rotateRadians(0, 0, point1, point2, angle);
        point1 = rotatedPoints[0];
        point2 = rotatedPoints[1];
        return {x: point1, y: point2};
    },
    async exportIFCProperties(){ 
      const container = document.createElement('div');
