        //const ifcModel = await viewer.IFC.loadIfcUrl(fileurl);
        const ifcModel = await ifcLoader.loadAsync(fileurl);
        const modelID = ifcModel.modelID;
        console.log("ModelID: "+modelID);
        const storeys = await ifcLoader.ifcManager.getAllItemsOfType(modelID, IFCBUILDINGSTOREY, false);
        for(let i=0; i<storeys.length; i++){
          const storey = await ifcLoader.ifcManager.getItemProperties(modelID, storeys[i]);
          this.floorlist.push(storey.Name.value);
        }
      } catch (error) {
        console.log(error);
      }
    },
    getFloorTagfromJson(jsonResult, IFCfloorName){
      for(let o=0; o<=Object.keys(jsonResult.storeys).length; o++){
        if(Object.values(jsonResult.storeys)[o]==IFCfloorName) return Object.keys(jsonResult.storeys)[o];
      }
      return "";
    },
    createPlaceMarker(pos, color, removePrevious){
      const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
      const previousPlacemarker = store.state.bv.scene.getObjectByName("placemarker");
      if(previousPlacemarker && removePrevious){
        buildingbox.remove(previousPlacemarker);
      }
      const material = new MeshLambertMaterial({
          transparent: true,
          opacity: 0.6,
          color: color,
          depthTest: true
      });
      const geometry = new BoxGeometry(0.2, 10.0, 0.2);
      geometry.translate(pos.x,pos.y,pos.z);
      const marker = new Mesh(geometry, material);
      marker.name = "placemarker";
      buildingbox.add(marker);
      return marker;
    },
  },
