<script>
import i18n from './plugins/i18n.js'
import store from './store';

export default {
  name: 'App',

  data: () => ({
      languages: [
          { flag: 'us', language: 'en' },
          { flag: 'no', language: 'no' }
      ],
      isLoggedIn: false,
      webId: "",
      loggedInName: "",
      loggedInInitials: "",
      loginExpire: "",
      window: {
        width: 0,
        height: 0
      }
  }),
  created() {
    window.addEventListener('resize', this.handleResize);
    this.handleResize();
  },
  destroyed() {
    window.removeEventListener('resize', this.handleResize);
  },
  methods: {
    changeLocale(locale) {
      i18n.locale = locale;
    },
    followLink(linkName){
      if(!this.$route.path.includes(linkName)){
        this.$router.push({path: linkName, query: {location: this.$route.query.location, select: this.$route.query.select} });
      }
    },
    handleResize() {
      this.window.width = window.innerWidth;
      this.window.height = window.innerHeight;
    }
  },
  watch: {
    "$store.state.isLoggedIn": function (val) {
      this.isLoggedIn = store.state.isLoggedIn;
    },
    "$store.state.webId": function (val) {
      this.webId = store.state.webId;
    },
    "$store.state.loggedInName": function (val) {
      this.loggedInName = store.state.loggedInName;
    },
    "$store.state.loggedInInitials": function (val) {
      this.loggedInInitials = store.state.loggedInInitials;
    },
    "$store.state.loginExpire": function (val) {
      this.loginExpire = store.state.loginExpire;
    }
  }
};
</script>
