const u = {};

import $ from 'jquery';
const $rdf = require('rdflib');
import store from '../store';

u.unique = function(array) {
  if (Array.isArray(array)) {
    return array.filter(function(a) {
      return !this[a] ? (this[a] = true) : false;
    }, {});
  }
};

u.getURI = function(string) {
  if (typeof string === "array") {
    return $.map(string, function(item) {
      return u.getURL(item);
    });
  } else if (typeof string === "object") {
    if (string.termType === "NamedNode") {
      return string.value;
    }
  } else {
    if (typeof string === "string") {
      string = string.replace("<", "").replace(">", "");
    }
    return u.getURL(string);
  }
};

u.getURL = function(string) {
  var result;
  if (typeof string === "object") {
    if (string.termType === "NamedNode") {
      result = string.value;
    } else {
      result = string.uri;
    }
  }
  if (!result && (typeof string === "string")) {
    result = string;
  }
  if (result) {
    if (u.checkURL(result)) {
      return string;
    } else if (u.checkIRI(result)) {
      return string.substr(1, string.length - 2);
    } else {
      return null;
    }
  } else {
    return null;
  }
};

u.getIRI = function(string) {
  if (u.checkIRI(string)) {
    return string;
  } else if (u.checkURL(string)) {
    if (string.indexOf("?") > -1) {
      string = string.split("?")[0];
    }
    return "<" + string + ">";
  } else {
    return null;
  }
};

u.checkIRI = function(string) {
  if (typeof string === "string") {
    if (
      string.indexOf("<http") == 0 &&
      string.indexOf(">") > -1 &&
      string.indexOf("?") == -1
    ) {
      return true;
    } else {
      return false;
    }
  } else {
    return false;
  }
};

u.checkURL = function(string) {
  let url;
  try {
    url = new URL(string);
    return true;
  } catch (_) {
    return false;
  }
};

u.getBlankNode = function (label){
  let tempBlank = "";
  store.state.rs.bIndex.forEach((item, i) => {
    if(item.label == label){
      tempBlank = item.blank
      store.state.blankExisted = true
    }
  });
  if(tempBlank == ""){
    store.commit('blankNodeIncrement');
    tempBlank = $rdf.sym(store.state.blankNodeString);
    store.state.rs.bIndex.push({ "label": label, "blank": tempBlank });
    store.state.blankExisted = false
  }
  return tempBlank
}

u.isBlankNode = function(node){
  if ($.type(node) === 'object'){
    if (node.termType === 'BlankNode'){
        return true
    } else {
        return false
    }
      } else {
    return false
  }
}

u.prettyTAG = function(st) {
  let s = st.replaceAll(" ", "");
  s = s.replaceAll("Æ", "AE");
  s = s.replaceAll("Ø", "O");
  s = s.replaceAll("Å", "AA");
  s = s.replaceAll("æ", "ae");
  s = s.replaceAll("ø", "o");
  s = s.replaceAll("å", "aa");
  return s;
}

u.storeToTurtle = function(pStore, baseurl){
  var result
  $rdf.serialize(undefined, pStore, baseurl, 'text/turtle', function(err, str) {
      console.log("Turtle serialize error: ", err);
      result = str;
  });
  return result;
}

